// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

// Health endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Mount routes
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const errors = require('../../lib/errors');

let tasksStore = [];

function getTasks(projectId, statusFilter) {
  const projectTasks = tasksStore.filter(task => task.projectId === projectId);
  if (statusFilter) {
    return projectTasks.filter(task => task.status === statusFilter);
  }
  return projectTasks;
}

function updateTask(projectId, taskId, newStatus) {
  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    errors.sendError(res, 404, 'NOT_FOUND', 'Task not found');
    return null;
  }

  if (!['todo', 'done'].includes(newStatus)) {
    errors.sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
    return null;
  }

  tasksStore[taskIndex].status = newStatus;
  return tasksStore[taskIndex];
}

module.exports = {
  getTasks,
  updateTask
};

// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const errors = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const statusFilter = req.query.status;
  try {
    const tasks = tasksService.getTasks(projectId, statusFilter);
    res.json({ tasks });
  } catch (error) {
    errors.sendError(res, error.statusCode || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  try {
    const updatedTask = tasksService.updateTask(projectId, taskId, status);
    if (!updatedTask) return;
    res.json({ task: updatedTask });
  } catch (error) {
    errors.sendError(res, error.statusCode || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

