// src/modules/projects/routes.js
const express = require('express');
const router = express.Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  const { projectId } = req.params;
  try {
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = [];

async function getAllProjects() {
  return projectsStore.slice();
}

async function getProjectById(projectId) {
  return projectsStore.find(p => p.id === projectId);
}

async function createProject(name) {
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  getProjectById,
  createProject,
};
module.exports.getProjects = module.exports.getAllProjects;

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const member = await membersService.createMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const membersStore = [];

async function addMember(projectId, userId, role) {
  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = {
  addMember,
};
module.exports.createMember = module.exports.addMember;

// src/modules/comments/routes.js
const express = require('express');
const router = express.Router();
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const comment = await commentsService.createComment(taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, 'NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const commentsStore = [];

async function addComment(projectId, taskId, content) {
  const comment = { id: randomUUID(), projectId, taskId, content };
  commentsStore.push(comment);
  return comment;
}

module.exports = {
  addComment,
};
module.exports.createComment = module.exports.addComment;

// src/lib/errors.js
const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = {
  sendError,
};

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
